4	namespace app\service\security;
5	
6	class TaxIdEncryptionService
7	{
8	    private const CIPHER = 'aes-256-cbc';
9	
10	    /**
11	     * Encrypt a plaintext value using AES-256-CBC.
12	     * A random IV is generated and prepended to the ciphertext.
13	     *
14	     * @param string $plaintext
15	     * @return string Base64-encoded string containing IV + ciphertext.
16	     */
17	    public function encrypt(string $plaintext): string
18	    {
19	        $key = bootstrap_config('tax_id_encryption_key');
20	        $ivLength = openssl_cipher_iv_length(self::CIPHER);
21	        $iv = random_bytes($ivLength);
22	
23	        $ciphertext = openssl_encrypt($plaintext, self::CIPHER, $key, OPENSSL_RAW_DATA, $iv);
24	
25	        return base64_encode($iv . $ciphertext);
26	    }
27	
28	    /**
29	     * Decrypt a ciphertext value previously encrypted with encrypt().
30	     * Extracts the prepended IV before decrypting.
31	     *
32	     * @param string $ciphertext Base64-encoded string containing IV + ciphertext.
33	     * @return string The decrypted plaintext.
34	     */
35	    public function decrypt(string $ciphertext): string
36	    {
37	        $key = bootstrap_config('tax_id_encryption_key');
38	        $ivLength = openssl_cipher_iv_length(self::CIPHER);
39	
40	        $decoded = base64_decode($ciphertext, true);
41	        $iv = substr($decoded, 0, $ivLength);
42	        $encrypted = substr($decoded, $ivLength);
43	
44	        return openssl_decrypt($encrypted, self::CIPHER, $key, OPENSSL_RAW_DATA, $iv);
45	    }
46	}
