6	use think\facade\Db;
7	
8	class AuditHashService
9	{
10	    /**
11	     * Compute the entry hash from entry data and the previous hash.
12	     * Uses SHA-256 over canonical JSON concatenated with the previous hash.
13	     *
14	     * @param array  $entryData
15	     * @param string $prevHash
16	     * @return string Hex-encoded SHA-256 hash.
17	     */
18	    public function computeEntryHash(array $entryData, string $prevHash): string
19	    {
20	        $canonical = json_encode($entryData, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
21	        return hash('sha256', $canonical . $prevHash);
22	    }
23	
24	    /**
25	     * Get the entry_hash of the most recent audit log entry.
26	     * Returns a zero hash if no entries exist (genesis).
27	     *
28	     * @return string Hex-encoded hash.
29	     */
30	    public function getLatestHash(): string
31	    {
32	        $latest = Db::name('audit_logs')
33	            ->order('id', 'desc')
34	            ->value('entry_hash');
35	
36	        return $latest ?: str_repeat('0', 64);
37	    }
38	
39	    /**
40	     * Verify the integrity of the hash chain between two entry IDs.
41	     *
42	     * @param int $startId
43	     * @param int $endId
44	     * @return bool True if the chain is intact, false if any entry is tampered.
45	     */
46	    public function verifyChain(int $startId, int $endId): bool
47	    {
48	        $entries = Db::name('audit_logs')
49	            ->whereBetween('id', [$startId, $endId])
50	            ->order('id', 'asc')
51	            ->select()
52	            ->toArray();
53	
54	        foreach ($entries as $entry) {
55	            $entryData = [
56	                'event_type' => $entry['event_type'],
57	                'context'    => json_decode($entry['context'], true),
58	                'created_at' => $entry['created_at'],
59	            ];
60	
61	            $expected = $this->computeEntryHash($entryData, $entry['prev_hash']);
62	
63	            if ($expected !== $entry['entry_hash']) {
64	                return false;
65	            }
66	        }
67	
68	        return true;
69	    }
70	}
