6	class FieldMaskingService
7	{
8	    /**
9	     * Mask a value, showing only the last 4 characters.
10	     *
11	     * @param string $value  The value to mask.
12	     * @param string $policy Masking policy name (reserved for future policies).
13	     * @return string Masked value (e.g. '****5678').
14	     */
15	    public function mask(string $value, string $policy = 'default'): string
16	    {
17	        $length = mb_strlen($value);
18	        if ($length <= 4) {
19	            return str_repeat('*', $length);
20	        }
21	
22	        return str_repeat('*', $length - 4) . mb_substr($value, -4);
23	    }
24	
25	    /**
26	     * Determine whether a field should be masked given the user's roles.
27	     *
28	     * @param string $field     Field name.
29	     * @param array  $userRoles List of the requesting user's role identifiers.
30	     * @return bool True if the field should be masked for this user.
31	     */
32	    public function shouldMask(string $field, array $userRoles): bool
33	    {
34	        // TODO: Implement role-based masking policy lookup.
35	        // By default, mask unless the user has an admin or auditor role.
36	        $exemptRoles = ['admin', 'auditor'];
37	        return empty(array_intersect($userRoles, $exemptRoles));
38	    }
39	
40	    /**
41	     * Apply masking rules to an entire record.
42	     *
43	     * @param array $record         The data record (associative array).
44	     * @param array $maskableFields List of field names that are candidates for masking.
45	     * @param array $userRoles      The requesting user's role identifiers.
46	     * @return array The record with applicable fields masked.
47	     */
48	    public function applyMaskingToRecord(array $record, array $maskableFields, array $userRoles): array
49	    {
50	        foreach ($maskableFields as $field) {
51	            if (isset($record[$field]) && is_string($record[$field]) && $this->shouldMask($field, $userRoles)) {
52	                $record[$field] = $this->mask($record[$field]);
53	            }
54	        }
55	
56	        return $record;
57	    }
58	}
