6	use think\Request;
7	use think\Response;
8	use think\exception\HttpException;
9	
10	/**
11	 * CSRF protection for state-changing requests.
12	 *
13	 * Token is validated from the X-CSRF-Token header.
14	 * Token generation and refresh are handled by the auth flow.
15	 */
16	class CsrfMiddleware
17	{
18	    /** Methods that require CSRF validation */
19	    private const PROTECTED_METHODS = ['POST', 'PUT', 'PATCH', 'DELETE'];
20	
21	    /** Routes exempt from CSRF (login needs to work without a prior session) */
22	    private const EXEMPT_ROUTES = [
23	        'api/v1/auth/login',
24	        'api/v1/health',
25	    ];
26	
27	    public function handle(Request $request, \Closure $next): Response
28	    {
29	        $method = strtoupper($request->method());
30	
31	        if (!in_array($method, self::PROTECTED_METHODS)) {
32	            return $next($request);
33	        }
34	
35	        // Check exemptions
36	        $path = $request->pathinfo();
37	        foreach (self::EXEMPT_ROUTES as $exempt) {
38	            if (str_starts_with($path, $exempt)) {
39	                return $next($request);
40	            }
41	        }
42	
43	        $token = $request->header('X-CSRF-Token', '');
44	        $sessionToken = session('csrf_token');
45	
46	        if (empty($token) || empty($sessionToken) || !hash_equals($sessionToken, $token)) {
47	            throw new HttpException(403, 'CSRF token validation failed');
48	        }
49	
50	        return $next($request);
51	    }
52	}
