declare(strict_types=1);

namespace app\service\auth;

use think\facade\Db;

class AuthService
{
    private PasswordHashService $passwordHash;

    public function __construct(PasswordHashService $passwordHash)
    {
        $this->passwordHash = $passwordHash;
    }

    /**
     * Authenticate a user by username and password.
     *
     * @return array|null User data on success, null on failure.
     */
    public function attempt(string $username, string $password): ?array
    {
        $user = Db::name('users')
            ->where('username', $username)
            ->where('status', 'active')
            ->find();

        if (!$user) {
            return null;
        }

        if (!$this->passwordHash->verify($password, $user['password_hash'])) {
            return null;
        }

        // Rehash if algorithm/cost changed
        if ($this->passwordHash->needsRehash($user['password_hash'])) {
            Db::name('users')
                ->where('id', $user['id'])
                ->update(['password_hash' => $this->passwordHash->hash($password)]);
        }

        return [
            'id'           => (int)$user['id'],
            'username'     => $user['username'],
            'display_name' => $user['display_name'],
        ];
    }

    /**
     * Resolve roles and site scopes for a user.
     */
    public function resolveUserRolesAndScopes(int $userId): array
    {
        $roles = Db::name('user_roles')
            ->alias('ur')
            ->join('roles r', 'ur.role_id = r.id')
            ->where('ur.user_id', $userId)
            ->column('r.name');

        $siteScopes = Db::name('user_site_scopes')
            ->where('user_id', $userId)
            ->column('site_id');

        return [
            'roles'       => $roles,
            'site_scopes' => $siteScopes,
        ];
    }
}
"}

{"file_path": "/home/nico/Work/week-2/TASK-82/repo/app/controller/api/v1/AuthController.php", "content": "<?php
declare(strict_types=1);

namespace app\controller\api\v1;

use app\controller\BaseController;
use app\service\auth\AuthService;
use think\Response;

class AuthController extends BaseController
{
    /**
     * POST /api/v1/auth/login
     */
    public function login(AuthService $authService): Response
    {
        $username = $this->request->post('username', '');
        $password = $this->request->post('password', '');

        if (empty($username) || empty($password)) {
            return $this->error('VALIDATION_FAILED', 'Username and password are required.', [], 422);
        }

        $user = $authService->attempt($username, $password);

        if (!$user) {
            return $this->error('AUTH_INVALID_CREDENTIALS', 'Invalid credentials.', [], 401);
        }

        // Resolve roles and scopes
        $rolesAndScopes = $authService->resolveUserRolesAndScopes($user['id']);

        // Establish session
        session('user_id', $user['id']);
        session('user_roles', $rolesAndScopes['roles']);
        session('user_site_scopes', $rolesAndScopes['site_scopes']);

        // Generate CSRF token for session
        $csrfToken = bin2hex(random_bytes(32));
        session('csrf_token', $csrfToken);

        return $this->success([
            'user' => [
                'id'           => $user['id'],
                'username'     => $user['username'],
                'display_name' => $user['display_name'],
                'roles'        => $rolesAndScopes['roles'],
                'site_scopes'  => $rolesAndScopes['site_scopes'],
            ],
            'csrf_token' => $csrfToken,
        ]);
    }

    /**
     * POST /api/v1/auth/logout
     */
    public function logout(): Response
    {
        session(null);
        return $this->success(['message' => 'Logged out successfully.']);
    }

    /**
     * GET /api/v1/auth/me
     */
    public function me(): Response
    {
        return $this->success([
            'user_id'     => $this->request->userId,
            'roles'       => $this->request->roles,
            'site_scopes' => $this->request->siteScopes,
            'csrf_token'  => session('csrf_token') ?: '',
        ]);
    }
}
"}

