declare(strict_types=1);

namespace app\service\audit;

use think\facade\Db;

class AuditService
{
    protected AuditHashService $hashService;

    public function __construct(AuditHashService $hashService)
    {
        $this->hashService = $hashService;
    }

    /**
     * Append an immutable audit log entry with hash-chain integrity.
     *
     * All parameters map directly to audit_logs schema columns.
     */
    public function log(
        string $eventType,
        int    $actorId,
        string $actorRole,
        ?int   $siteId,
        string $targetType,
        ?int   $targetId,
        string $requestId,
        ?string $payloadSummary = null
    ): void {
        $prevHash = $this->hashService->getLatestHash();

        $entryData = [
            'event_type'      => $eventType,
            'actor_id'        => $actorId,
            'actor_role'      => $actorRole,
            'site_id'         => $siteId,
            'target_type'     => $targetType,
            'target_id'       => $targetId,
            'request_id'      => $requestId,
            'payload_summary' => $payloadSummary,
            'created_at'      => date('Y-m-d H:i:s'),
        ];

        $entryHash = $this->hashService->computeEntryHash($entryData, $prevHash);

        Db::name('audit_logs')->insert([
            'event_type'      => $eventType,
            'actor_id'        => $actorId,
            'actor_role'      => $actorRole,
            'site_id'         => $siteId,
            'target_type'     => $targetType,
            'target_id'       => $targetId,
            'request_id'      => $requestId,
            'payload_summary' => $payloadSummary,
            'prev_hash'       => $prevHash,
            'entry_hash'      => $entryHash,
            'created_at'      => $entryData['created_at'],
        ]);
    }

    /**
     * Query audit log entries by filters.
     */
    public function query(array $filters): array
    {
        $query = Db::name('audit_logs');

        if (!empty($filters['event_type'])) {
            $query->where('event_type', $filters['event_type']);
        }
        if (!empty($filters['actor_id'])) {
            $query->where('actor_id', $filters['actor_id']);
        }
        if (!empty($filters['site_id'])) {
            $query->where('site_id', $filters['site_id']);
        }
        if (!empty($filters['target_type'])) {
            $query->where('target_type', $filters['target_type']);
        }

        return $query->order('id', 'desc')->limit(100)->select()->toArray();
    }

    /**
     * Find a single audit log entry by ID.
     */
    public function findEntry(int $id): ?array
    {
        $entry = Db::name('audit_logs')->where('id', $id)->find();
        return $entry ?: null;
    }
}
"}

{"file_path": "/home/nico/Work/week-2/TASK-82/repo/app/service/audit/AuditHashService.php", "content": "<?php
declare(strict_types=1);

namespace app\service\audit;

use think\facade\Db;

class AuditHashService
{
    /**
     * Compute the entry hash from entry data and the previous hash.
     * Uses SHA-256 over canonical JSON concatenated with the previous hash.
     */
    public function computeEntryHash(array $entryData, string $prevHash): string
    {
        $canonical = json_encode($entryData, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
        return hash('sha256', $canonical . $prevHash);
    }

    /**
     * Get the entry_hash of the most recent audit log entry.
     * Returns a zero hash if no entries exist (genesis).
     */
    public function getLatestHash(): string
    {
        $latest = Db::name('audit_logs')
            ->order('id', 'desc')
            ->value('entry_hash');

        return $latest ?: str_repeat('0', 64);
    }

    /**
     * Verify the integrity of the hash chain between two entry IDs.
     */
    public function verifyChain(int $startId, int $endId): bool
    {
        $entries = Db::name('audit_logs')
            ->whereBetween('id', [$startId, $endId])
            ->order('id', 'asc')
            ->select()
            ->toArray();

        foreach ($entries as $entry) {
            // Reconstruct the entry data used for hashing — must match AuditService::log
            $entryData = [
                'event_type'      => $entry['event_type'],
                'actor_id'        => (int)$entry['actor_id'],
                'actor_role'      => $entry['actor_role'],
                'site_id'         => $entry['site_id'] !== null ? (int)$entry['site_id'] : null,
                'target_type'     => $entry['target_type'],
                'target_id'       => $entry['target_id'] !== null ? (int)$entry['target_id'] : null,
                'request_id'      => $entry['request_id'],
                'payload_summary' => $entry['payload_summary'],
                'created_at'      => $entry['created_at'],
            ];

            $expected = $this->computeEntryHash($entryData, $entry['prev_hash']);

            if ($expected !== $entry['entry_hash']) {
                return false;
            }
        }

        return true;
    }
}
"}

