declare(strict_types=1);

namespace app\job;

use think\console\Command;
use think\console\Input;
use think\console\Output;
use think\facade\Db;
use app\service\auth\PasswordHashService;

/**
 * Seeds a dev admin user from bootstrap config.
 * Idempotent: skips if admin user already exists.
 */
class SeedAdminCommand extends Command
{
    protected function configure(): void
    {
        $this->setName('seed:admin')
            ->setDescription('Seed local-dev admin user from bootstrap config');
    }

    protected function execute(Input $input, Output $output): int
    {
        $password = bootstrap_config('seed_admin_password', '');
        if (empty($password)) {
            $output->writeln('No seed_admin_password in bootstrap config, skipping.');
            return 0;
        }

        $existing = Db::name('users')->where('username', 'admin')->find();
        if ($existing) {
            $output->writeln('Admin user already exists, skipping seed.');
            return 0;
        }

        $hashService = new PasswordHashService();

        // Create admin user
        $userId = Db::name('users')->insertGetId([
            'username'      => 'admin',
            'password_hash' => $hashService->hash($password),
            'display_name'  => 'Administrator',
            'status'        => 'active',
            'created_at'    => date('Y-m-d H:i:s'),
            'updated_at'    => date('Y-m-d H:i:s'),
        ]);

        // Create administrator role if not exists
        $role = Db::name('roles')->where('name', 'administrator')->find();
        if (!$role) {
            $roleId = Db::name('roles')->insertGetId([
                'name'         => 'administrator',
                'display_name' => 'Administrator',
                'description'  => 'Full system access',
                'created_at'   => date('Y-m-d H:i:s'),
            ]);
        } else {
            $roleId = $role['id'];
        }

        // Assign role to user
        Db::name('user_roles')->insert([
            'user_id'    => $userId,
            'role_id'    => $roleId,
            'created_at' => date('Y-m-d H:i:s'),
        ]);

        // Create a default site
        $site = Db::name('sites')->where('code', 'HQ')->find();
        if (!$site) {
            $siteId = Db::name('sites')->insertGetId([
                'name'       => 'Headquarters',
                'code'       => 'HQ',
                'status'     => 'active',
                'created_at' => date('Y-m-d H:i:s'),
                'updated_at' => date('Y-m-d H:i:s'),
            ]);
        } else {
            $siteId = $site['id'];
        }

        // Assign site scope
        Db::name('user_site_scopes')->insert([
            'user_id'    => $userId,
            'site_id'    => $siteId,
            'created_at' => date('Y-m-d H:i:s'),
        ]);

        $output->writeln("Dev admin user seeded: username=admin");
        return 0;
    }
}
"}

