10	/**
11	 * Role-based access control middleware.
12	 *
13	 * Usage in routes: ->middleware('rbac:admin,auditor')
14	 * The parameter is a comma-separated list of allowed role names.
15	 */
16	class RbacMiddleware
17	{
18	    public function handle(Request $request, \Closure $next, ?string $allowedRoles = null): Response
19	    {
20	        if (!$request->userId) {
21	            throw new HttpException(401, 'Authentication required');
22	        }
23	
24	        if ($allowedRoles !== null) {
25	            $allowed = array_map('trim', explode(',', $allowedRoles));
26	            $userRoles = $request->roles ?: [];
27	
28	            $hasPermission = !empty(array_intersect($userRoles, $allowed));
29	            if (!$hasPermission) {
30	                throw new HttpException(403, 'Insufficient role permissions');
31	            }
32	        }
33	
34	        return $next($request);
35	    }
36	}
