1	<?php
2	declare(strict_types=1);
3	
4	namespace app\controller\api\v1;
5	
6	use app\controller\BaseController;
7	use app\model\Recipe;
8	use app\model\RecipeVersion;
9	use app\model\ReviewComment;
10	use app\service\recipe\RecipeService;
11	use app\service\recipe\WorkflowService;
12	use app\validate\RecipeValidate;
13	use app\validate\RecipeVersionValidate;
14	use think\exception\ValidateException;
15	use think\Response;
16	
17	class RecipeController extends BaseController
18	{
19	    /**
20	     * GET /api/v1/recipes
21	     *
22	     * List recipes with pagination.
23	     */
24	    public function index(RecipeService $recipeService): Response
25	    {
26	        $filters = [
27	            'status'   => $this->request->get('status'),
28	            'category' => $this->request->get('category'),
29	            'page'     => (int) $this->request->get('page', 1),
30	            'per_page' => (int) $this->request->get('per_page', 20),
31	        ];
32	
33	        $page    = max(1, $filters['page']);
34	        $perPage = min(100, max(1, $filters['per_page']));
35	
36	        $query = Recipe::order('created_at', 'desc');
37	        $this->applySiteScope($query);
38	
39	        if (!empty($filters['status'])) {
40	            $query->where('status', $filters['status']);
41	        }
42	        if (!empty($filters['category'])) {
43	            $query->where('category', $filters['category']);
44	        }
45	
46	        $total      = $query->count();
47	        $totalPages = (int) ceil($total / $perPage);
48	        $items      = $query->page($page, $perPage)
49	                            ->select()
50	                            ->toArray();
51	
52	        return $this->success([
53	            'items'      => $items,
54	            'pagination' => [
55	                'page'        => $page,
56	                'per_page'    => $perPage,
57	                'total'       => $total,
58	                'total_pages' => $totalPages,
59	            ],
60	        ]);
61	    }
62	
63	    /**
64	     * POST /api/v1/recipes
65	     *
66	     * Create a new recipe.
67	     */
68	    public function create(RecipeService $recipeService): Response
69	    {
70	        $input = json_decode($this->request->getInput(), true) ?: [];
71	
72	        try {
73	            validate(RecipeValidate::class)->scene('create')->check($input);
74	        } catch (ValidateException $e) {
75	            return $this->error('VALIDATION_FAILED', $e->getMessage(), [], 422);
76	        }
77	
78	        $siteId = (int) $input['site_id'];
79	        if (!$this->canAccessSite($siteId)) {
80	            return $this->error('FORBIDDEN_SITE_SCOPE', 'You do not have access to this site.', [], 403);
81	        }
82	
83	        $data = $recipeService->create([
84	            'title'      => $input['title'],
85	            'site_id'    => $siteId,
86	            'status'     => 'draft',
87	            'created_by' => $this->request->userId,
88	        ], $this->request->userId);
89	
90	        return $this->success([
91	            'id'      => $data['id'] ?? null,
92	            'message' => 'Recipe created.',
93	        ], 201);
94	    }
95	
96	    /**
97	     * GET /api/v1/recipes/:id
98	     *
99	     * Read a single recipe.
100	     */
101	    public function read($id, RecipeService $recipeService): Response
102	    {
103	        $recipe = $recipeService->find((int) $id, $this->request->siteScopes);
104	
105	        if (!$recipe) {
106	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
107	        }
108	
109	        $versions = RecipeVersion::where('recipe_id', (int) $id)
110	            ->order('version_number', 'desc')
111	            ->select()
112	            ->toArray();
113	
114	        $recipe['versions'] = $versions;
115	
116	        return $this->success($recipe);
117	    }
118	
119	    /**
120	     * POST /api/v1/recipes/:id/versions
121	     *
122	     * Create a new version (draft) of an existing recipe.
123	     */
124	    public function createVersion($id, RecipeService $recipeService): Response
125	    {
126	        $recipe = $recipeService->find((int) $id, $this->request->siteScopes);
127	
128	        if (!$recipe) {
129	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
130	        }
131	
132	        $input = json_decode($this->request->getInput(), true) ?: [];
133	
134	        $version = $recipeService->createVersion((int) $id, array_merge($input, [
135	            'created_by' => $this->request->userId,
136	        ]));
137	
138	        return $this->success([
139	            'recipe_id' => (int) $id,
140	            'version'   => $version,
141	            'message'   => 'New version created.',
142	        ], 201);
143	    }
144	
145	    /**
146	     * PUT /api/v1/recipes/:id/versions
147	     *
148	     * Update the current draft version of a recipe.
149	     */
150	    public function updateVersion($id, RecipeService $recipeService): Response
151	    {
152	        $recipe = $recipeService->find((int) $id, $this->request->siteScopes);
153	
154	        if (!$recipe) {
155	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
156	        }
157	
158	        $input = json_decode($this->request->getInput(), true) ?: [];
159	
160	        try {
161	            validate(RecipeVersionValidate::class)->check($input);
162	        } catch (ValidateException $e) {
163	            return $this->error('VALIDATION_FAILED', $e->getMessage(), [], 422);
164	        }
165	
166	        $draftVersion = RecipeVersion::where('recipe_id', (int) $id)
167	            ->where('status', 'Draft')
168	            ->order('version_number', 'desc')
169	            ->find();
170	
171	        if (!$draftVersion) {
172	            return $this->error('WORKFLOW_CONFLICT', 'No draft version exists for this recipe.', [], 409);
173	        }
174	
175	        $draftVersion->save([
176	            'content_json' => isset($input['steps']) ? json_encode($input['steps']) : $draftVersion->content_json,
177	            'total_time'   => $input['total_time'] ?? $draftVersion->total_time,
178	            'difficulty'   => $input['difficulty'] ?? $draftVersion->difficulty,
179	            'prep_time'    => $input['prep_time'] ?? $draftVersion->prep_time,
180	            'cook_time'    => $input['cook_time'] ?? $draftVersion->cook_time,
181	        ]);
182	
183	        return $this->success([
184	            'recipe_id' => (int) $id,
185	            'message'   => 'Version updated.',
186	        ]);
187	    }
188	
189	    /**
190	     * POST /api/v1/recipes/:id/review
191	     *
192	     * Submit a recipe version for review.
193	     */
194	    public function submitReview($id, RecipeService $recipeService, WorkflowService $workflowService): Response
195	    {
196	        $recipe = $recipeService->find((int) $id, $this->request->siteScopes);
197	
198	        if (!$recipe) {
199	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
200	        }
201	
202	        $draftVersion = RecipeVersion::where('recipe_id', (int) $id)
203	            ->where('status', 'Draft')
204	            ->order('version_number', 'desc')
205	            ->find();
206	
207	        if (!$draftVersion) {
208	            return $this->error('WORKFLOW_CONFLICT', 'No draft version to submit.', [], 409);
209	        }
210	
211	        try {
212	            $workflowService->submitForReview($draftVersion->id);
213	        } catch (ValidateException $e) {
214	            return $this->error('WORKFLOW_CONFLICT', $e->getMessage(), [], 409);
215	        }
216	
217	        return $this->success([
218	            'recipe_id' => (int) $id,
219	            'status'    => 'pending_review',
220	            'message'   => 'Recipe submitted for review.',
221	        ]);
222	    }
223	
224	    /**
225	     * GET /api/v1/recipes/:id/diff
226	     *
227	     * Show the diff between version and previous version.
228	     */
229	    public function diff($id, RecipeService $recipeService): Response
230	    {
231	        $recipe = $recipeService->find((int) $id, $this->request->siteScopes);
232	
233	        if (!$recipe) {
234	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
235	        }
236	
237	        $versions = RecipeVersion::where('recipe_id', (int) $id)
238	            ->order('version_number', 'desc')
239	            ->limit(2)
240	            ->select()
241	            ->toArray();
242	
243	        if (count($versions) < 2) {
244	            return $this->success([
245	                'recipe_id' => (int) $id,
246	                'changes'   => [],
247	                'message'   => 'No previous version to compare.',
248	            ]);
249	        }
250	
251	        $current  = $versions[0];
252	        $previous = $versions[1];
253	        $changes  = [];
254	
255	        $currentContent  = json_decode($current['content_json'] ?? '[]', true) ?: [];
256	        $previousContent = json_decode($previous['content_json'] ?? '[]', true) ?: [];
257	
258	        foreach (['total_time', 'difficulty', 'prep_time', 'cook_time'] as $field) {
259	            if (($current[$field] ?? null) !== ($previous[$field] ?? null)) {
260	                $changes[] = [
261	                    'field' => $field,
262	                    'old'   => $previous[$field] ?? null,
263	                    'new'   => $current[$field] ?? null,
264	                ];
265	            }
266	        }
267	
268	        if ($currentContent !== $previousContent) {
269	            $changes[] = [
270	                'field' => 'steps',
271	                'old'   => $previousContent,
272	                'new'   => $currentContent,
273	            ];
274	        }
275	
276	        return $this->success([
277	            'recipe_id'        => (int) $id,
