41	    /**
42	     * Approve a recipe version.
43	     * Transitions: in_review -> approved.
44	     *
45	     * @param int         $versionId
46	     * @param int         $reviewerId
47	     * @param string|null $comment
48	     * @return void
49	     * @throws ValidateException If the current state does not allow this transition.
50	     */
51	    public function approve(int $versionId, int $reviewerId, ?string $comment = null): void
52	    {
53	        $currentState = $this->resolveCurrentState($versionId);
54	        $this->assertTransition($currentState, 'approved');
55	
56	        $now = date('Y-m-d H:i:s');
57	
58	        Db::startTrans();
59	        try {
60	            Db::table('recipe_versions')
61	                ->where('id', $versionId)
62	                ->update([
63	                    'status' => 'approved',
64	                    'reviewer_id' => $reviewerId,
65	                    'reviewed_at' => $now,
66	                    'updated_at' => $now,
67	                ]);
68	
69	            Db::table('review_actions')->insert([
70	                'version_id' => $versionId,
71	                'reviewer_id' => $reviewerId,
72	                'action' => 'approved',
73	                'comment' => $comment,
74	                'created_at' => $now,
75	            ]);
76	
77	            Db::commit();
78	        } catch (\Throwable $e) {
79	            Db::rollback();
80	            throw $e;
81	        }
82	    }
