84	    /**
85	     * Reject a recipe version.
86	     * Transitions: in_review -> rejected.
87	     *
88	     * @param int         $versionId
89	     * @param int         $reviewerId
90	     * @param string|null $comment
91	     * @return void
92	     * @throws ValidateException If the current state does not allow this transition.
93	     */
94	    public function reject(int $versionId, int $reviewerId, ?string $comment = null): void
95	    {
96	        $currentState = $this->resolveCurrentState($versionId);
97	        $this->assertTransition($currentState, 'rejected');
98	
99	        $now = date('Y-m-d H:i:s');
100	
101	        Db::startTrans();
102	        try {
103	            Db::table('recipe_versions')
104	                ->where('id', $versionId)
105	                ->update([
106	                    'status' => 'rejected',
107	                    'reviewer_id' => $reviewerId,
108	                    'reviewed_at' => $now,
109	                    'updated_at' => $now,
110	                ]);
111	
112	            Db::table('review_actions')->insert([
113	                'version_id' => $versionId,
114	                'reviewer_id' => $reviewerId,
115	                'action' => 'rejected',
116	                'comment' => $comment,
117	                'created_at' => $now,
