127	    /**
128	     * Publish an approved recipe version.
129	     * Sets published_version_id on the recipe and updates recipe status.
130	     *
131	     * @param int $recipeId
132	     * @param int $userId
133	     * @return void
134	     * @throws ValidateException If no approved version exists for the recipe.
135	     */
136	    public function publish(int $recipeId, int $userId): void
137	    {
138	        // Find the latest approved version for this recipe
139	        $version = Db::table('recipe_versions')
140	            ->where('recipe_id', $recipeId)
141	            ->where('status', 'approved')
142	            ->order('version_number', 'desc')
143	            ->find();
144	
145	        if (!$version) {
146	            throw new ValidateException('Only approved versions can be published.');
147	        }
148	
149	        Db::table('recipes')
150	            ->where('id', $recipeId)
151	            ->update([
152	                'published_version_id' => $version['id'],
153	                'status' => 'published',
154	                'updated_at' => date('Y-m-d H:i:s'),
155	            ]);
156	    }
157	
158	    /**
159	     * Resolve the current workflow state of a recipe version.
160	     *
161	     * @param int $versionId
162	     * @return string Current state name (draft, in_review, approved, rejected).
163	     * @throws ValidateException If version not found.
164	     */
165	    private function resolveCurrentState(int $versionId): string
166	    {
167	        $version = Db::table('recipe_versions')
168	            ->where('id', $versionId)
169	            ->field('status')
170	            ->find();
171	
172	        if (!$version) {
173	            throw new ValidateException('Recipe version not found.');
174	        }
175	
176	        return $version['status'];
177	    }
178	
179	    /**
180	     * Assert that a transition from the current state to the target state is valid.
181	     *
182	     * @param string $currentState
183	     * @param string $targetState
184	     * @return void
185	     * @throws ValidateException If the transition is not allowed.
186	     */
187	    private function assertTransition(string $currentState, string $targetState): void
188	    {
189	        $allowed = self::TRANSITIONS[$currentState] ?? [];
190	        if (!in_array($targetState, $allowed, true)) {
191	            throw new ValidateException(
192	                "Invalid state transition: {$currentState} -> {$targetState}"
193	            );
194	        }
195	    }
196	}
