11	    /**
12	     * Generate a settlement statement for a site and period.
13	     * Creates settlement_lines from orders for that site+period and calculates total.
14	     *
15	     * @param int    $siteId
16	     * @param string $period Period identifier (e.g. '2026-03').
17	     * @param int    $userId Generating user ID.
18	     * @return array The generated statement record.
19	     */
20	    public function generate(int $siteId, string $period, int $userId): array
21	    {
22	        $now = date('Y-m-d H:i:s');
23	
24	        // Determine date range from period (YYYY-MM format)
25	        $periodStart = $period . '-01';
26	        $periodEnd = date('Y-m-t 23:59:59', strtotime($periodStart));
27	        $periodStart .= ' 00:00:00';
28	
29	        Db::startTrans();
30	        try {
31	            // Create statement with draft status
32	            $statementId = Db::table('settlement_statements')->insertGetId([
33	                'site_id' => $siteId,
34	                'period' => $period,
35	                'status' => 'draft',
36	                'total_amount' => 0,
37	                'generated_by' => $userId,
38	                'created_at' => $now,
39	                'updated_at' => $now,
40	            ]);
41	
42	            // Fetch orders for this site and period
43	            $orders = Db::table('orders')
44	                ->where('site_id', $siteId)
45	                ->where('created_at', '>=', $periodStart)
46	                ->where('created_at', '<=', $periodEnd)
47	                ->select()
48	                ->toArray();
49	
50	            $totalAmount = 0;
51	
52	            foreach ($orders as $order) {
53	                $amount = (float) $order['total_amount'];
54	                $totalAmount += $amount;
55	
56	                Db::table('settlement_lines')->insert([
57	                    'statement_id' => $statementId,
58	                    'description' => 'Order #' . $order['id'],
59	                    'amount' => $amount,
60	                    'category' => 'order',
61	                    'created_at' => $now,
62	                ]);
63	            }
64	
65	            // Account for refunds in the period
66	            $refunds = Db::table('refunds')
67	                ->alias('ref')
68	                ->join('orders o', 'o.id = ref.order_id')
69	                ->where('o.site_id', $siteId)
70	                ->where('ref.created_at', '>=', $periodStart)
71	                ->where('ref.created_at', '<=', $periodEnd)
72	                ->field('ref.*')
73	                ->select()
74	                ->toArray();
75	
76	            foreach ($refunds as $refund) {
77	                $amount = -1 * abs((float) $refund['amount']);
78	                $totalAmount += $amount;
79	
80	                Db::table('settlement_lines')->insert([
81	                    'statement_id' => $statementId,
82	                    'description' => 'Refund for Order #' . $refund['order_id'],
83	                    'amount' => $amount,
84	                    'category' => 'refund',
85	                    'created_at' => $now,
86	                ]);
87	            }
88	
89	            // Update statement total
90	            Db::table('settlement_statements')
91	                ->where('id', $statementId)
92	                ->update(['total_amount' => round($totalAmount, 2)]);
93	
94	            Db::commit();
95	        } catch (\Throwable $e) {
96	            Db::rollback();
97	            throw $e;
98	        }
99	
100	        return Db::table('settlement_statements')->where('id', $statementId)->find();
101	    }
