137	                'actor_id' => $clerkId,
138	                'action' => 'submitted',
139	                'created_at' => $now,
140	            ]);
141	
142	            Db::commit();
143	        } catch (\Throwable $e) {
144	            Db::rollback();
145	            throw $e;
146	        }
147	    }
