195	    /**
196	     * Reverse a previously approved statement.
197	     * Creates a settlement_reversal and a new draft replacement statement.
198	     * Only works on approved_locked statements.
199	     *
200	     * @param int    $statementId
201	     * @param int    $actorId
202	     * @param string $reason Reason for reversal.
203	     * @return array The reversal record including replacement_statement_id.
204	     * @throws ValidateException If the statement is not in approved_locked status.
205	     */
206	    public function reverse(int $statementId, int $actorId, string $reason): array
207	    {
208	        $statement = Db::table('settlement_statements')->where('id', $statementId)->find();
209	        if (!$statement) {
210	            throw new ValidateException('Statement not found.');
211	        }
212	        if ($statement['status'] !== 'approved_locked') {
213	            throw new ValidateException('Only approved_locked statements can be reversed.');
214	        }
215	
216	        $now = date('Y-m-d H:i:s');
217	
218	        Db::startTrans();
219	        try {
220	            // Mark original as reversed
221	            Db::table('settlement_statements')
222	                ->where('id', $statementId)
223	                ->update([
224	                    'status' => 'reversed',
225	                    'updated_at' => $now,
226	                ]);
227	
228	            // Create new draft replacement statement
229	            $replacementId = Db::table('settlement_statements')->insertGetId([
230	                'site_id' => $statement['site_id'],
231	                'period' => $statement['period'],
232	                'status' => 'draft',
233	                'total_amount' => $statement['total_amount'],
234	                'generated_by' => $actorId,
235	                'created_at' => $now,
236	                'updated_at' => $now,
237	            ]);
238	
239	            // Copy settlement lines to replacement
240	            $lines = Db::table('settlement_lines')
241	                ->where('statement_id', $statementId)
242	                ->select()
243	                ->toArray();
244	
245	            foreach ($lines as $line) {
246	                Db::table('settlement_lines')->insert([
247	                    'statement_id' => $replacementId,
248	                    'description' => $line['description'],
249	                    'amount' => $line['amount'],
250	                    'category' => $line['category'],
251	                    'created_at' => $now,
252	                ]);
253	            }
254	
255	            // Create reversal record
256	            $reversalId = Db::table('settlement_reversals')->insertGetId([
257	                'original_statement_id' => $statementId,
258	                'replacement_statement_id' => $replacementId,
259	                'reason' => $reason,
260	                'reversed_by' => $actorId,
261	                'created_at' => $now,
262	            ]);
263	
264	            Db::commit();
265	        } catch (\Throwable $e) {
266	            Db::rollback();
267	            throw $e;
268	        }
269	
270	        return Db::table('settlement_reversals')->where('id', $reversalId)->find();
271	    }
