{"file_path": "/home/nico/Work/week-2/TASK-82/repo/tests/Playwright/helpers.ts", "content": "import { Page, expect } from '@playwright/test';
import { readFileSync } from 'fs';

export function getPassword(): string {
  try {
    return readFileSync('/tmp/siteops_test_password', 'utf-8').trim();
  } catch {
    throw new Error('Test password file not found at /tmp/siteops_test_password');
  }
}

export async function login(page: Page, username: string): Promise<string> {
  const password = getPassword();
  await page.goto('/login');
  await page.fill('input[name="username"]', username);
  await page.fill('input[name="password"]', password);
  await page.click('button[lay-submit]');
  // Wait for redirect to dashboard
  await page.waitForURL('**/dashboard', { timeout: 10000 });
  // Get CSRF token from meta tag
  const csrf = await page.getAttribute('meta[name="csrf-token"]', 'content') || '';
  return csrf;
}

export async function apiPost(page: Page, path: string, data: any, csrf: string): Promise<any> {
  const response = await page.request.post(`http://127.0.0.1:8080${path}`, {
    data,
    headers: {
      'Content-Type': 'application/json',
      'X-CSRF-Token': csrf,
    },
  });
  return { status: response.status(), body: await response.json() };
}

export async function apiGet(page: Page, path: string): Promise<any> {
  const response = await page.request.get(`http://127.0.0.1:8080${path}`);
  return { status: response.status(), body: await response.json() };
}
"}

