import { login, apiPost, apiGet } from './helpers';

test.describe('Recipe Editor → Review → Publish Flow', () => {
  let editorCsrf: string;
  let reviewerCsrf: string;

  test('editor creates recipe, updates version, submits for review', async ({ page }) => {
    editorCsrf = await login(page, 'editor');

    // Navigate to recipe editor
    await page.goto('/recipes/editor');
    await page.waitForTimeout(1000);
    await page.screenshot({ path: 'tests/Playwright/artifacts/02-recipe-editor-page.png' });

    // Create recipe via API (same as what the UI "New Recipe" button does)
    const createRes = await apiPost(page, '/api/v1/recipes', { title: 'E2E Test Recipe', site_id: 1 }, editorCsrf);
    expect(createRes.status).toBe(201);
    const recipeId = createRes.body.data.id;

    // Get version ID
    const readRes = await apiGet(page, `/api/v1/recipes/${recipeId}`);
    expect(readRes.status).toBe(200);
    const versionId = readRes.body.data.versions[0].id;

    // Update version with content
    const updateRes = await apiPost(page, `/api/v1/recipe-versions/${versionId}`, {
      total_time: 30,
      difficulty: 'easy',
      steps: [
        { instruction: 'Boil water', duration_minutes: 5 },
        { instruction: 'Add ingredients', duration_minutes: 10 },
        { instruction: 'Simmer', duration_minutes: 15 },
      ],
      content_json: '<p>A simple test recipe for E2E verification.</p>',
    }, editorCsrf);
    // PUT on recipe-versions uses PUT method
    const putRes = await page.request.put(`http://127.0.0.1:8080/api/v1/recipe-versions/${versionId}`, {
      data: {
        total_time: 30,
        difficulty: 'easy',
        steps: [
          { instruction: 'Boil water', duration_minutes: 5 },
          { instruction: 'Add ingredients', duration_minutes: 10 },
          { instruction: 'Simmer', duration_minutes: 15 },
        ],
        content_json: '<p>A simple test recipe.</p>',
      },
      headers: { 'Content-Type': 'application/json', 'X-CSRF-Token': editorCsrf },
    });
    expect(putRes.status()).toBe(200);

    // Submit for review
    const submitRes = await apiPost(page, `/api/v1/recipe-versions/${versionId}/submit-review`, {}, editorCsrf);
    expect(submitRes.status).toBe(200);

    // Navigate to editor page and screenshot to show the recipe list
    await page.goto('/recipes/editor');
    await page.waitForTimeout(2000);
    await page.screenshot({ path: 'tests/Playwright/artifacts/02-recipe-list-after-create.png' });

    // Store IDs for next test via env (Playwright test isolation means we use API)
    test.info().annotations.push({ type: 'recipeId', description: String(recipeId) });
    test.info().annotations.push({ type: 'versionId', description: String(versionId) });
  });

  test('reviewer approves and recipe gets published', async ({ page }) => {
    reviewerCsrf = await login(page, 'reviewer');

    // Navigate to review page
    await page.goto('/recipes/review');
    await page.waitForTimeout(1500);
    await page.screenshot({ path: 'tests/Playwright/artifacts/02-review-queue.png' });

    // Find an in_review recipe via API
    const listRes = await apiGet(page, '/api/v1/recipes?status=in_review');
    const recipes = listRes.body.data?.items || [];

    if (recipes.length > 0) {
      const recipe = recipes[0];
      const recipeDetail = await apiGet(page, `/api/v1/recipes/${recipe.id}`);
      const versions = recipeDetail.body.data?.versions || [];
      const inReviewVersion = versions.find((v: any) => v.status === 'in_review');

      if (inReviewVersion) {
        // Add comment
        const commentRes = await apiPost(page, `/api/v1/recipe-versions/${inReviewVersion.id}/comments`, {
          content: 'Looks good, approved via E2E test',
          anchor_type: 'general',
        }, reviewerCsrf);
        expect(commentRes.status).toBe(201);

        // Approve
        const approveRes = await apiPost(page, `/api/v1/recipe-versions/${inReviewVersion.id}/approve`, {}, reviewerCsrf);
        expect(approveRes.status).toBe(200);

        // Publish
        const publishRes = await apiPost(page, `/api/v1/recipes/${recipe.id}/publish`, {}, reviewerCsrf);
        expect(publishRes.status).toBe(200);
      }
    }

    // Navigate to catalog
    await page.goto('/catalog');
    await page.waitForTimeout(1500);
    await page.screenshot({ path: 'tests/Playwright/artifacts/02-catalog-published.png' });

    // Verify catalog has published recipes via API
    const catalogRes = await apiGet(page, '/api/v1/catalog/recipes');
    expect(catalogRes.status).toBe(200);
    expect(catalogRes.body.data.items.length).toBeGreaterThan(0);
  });

  test('approved version is immutable', async ({ page }) => {
    editorCsrf = await login(page, 'editor');

    // Find a recipe with an approved version
    const listRes = await apiGet(page, '/api/v1/recipes?status=published');
    const recipes = listRes.body.data?.items || [];

    if (recipes.length > 0) {
      const detail = await apiGet(page, `/api/v1/recipes/${recipes[0].id}`);
      const versions = detail.body.data?.versions || [];
      const approved = versions.find((v: any) => v.status === 'approved');

      if (approved) {
        const res = await page.request.put(`http://127.0.0.1:8080/api/v1/recipe-versions/${approved.id}`, {
          data: { total_time: 999 },
          headers: { 'Content-Type': 'application/json', 'X-CSRF-Token': editorCsrf },
        });
        expect(res.status()).toBe(409);
      }
    }
  });
});
"}

