import { login, apiPost, apiGet } from './helpers';

test.describe('Settlement Flow', () => {
  test('finance clerk generates and submits statement', async ({ page }) => {
    const csrf = await login(page, 'finance');
    await page.goto('/settlements');
    await page.waitForTimeout(1500);
    await page.screenshot({ path: 'tests/Playwright/artifacts/04-settlement-page.png' });

    // Generate statement via API
    const genRes = await apiPost(page, '/api/v1/finance/settlements/generate', {
      site_id: 1,
      period: '2023-06',
    }, csrf);
    expect(genRes.status).toBe(200);
    const stmtId = genRes.body.data.settlement_id;
    expect(stmtId).toBeTruthy();

    // Read it
    const readRes = await apiGet(page, `/api/v1/finance/settlements/${stmtId}`);
    expect(readRes.status).toBe(200);
    expect(readRes.body.data.status).toBe('draft');

    // Submit
    const submitRes = await apiPost(page, `/api/v1/finance/settlements/${stmtId}/submit`, {}, csrf);
    expect(submitRes.status).toBe(200);

    await page.screenshot({ path: 'tests/Playwright/artifacts/04-settlement-submitted.png' });
    test.info().annotations.push({ type: 'stmtId', description: String(stmtId) });
  });

  test('finance clerk cannot approve-final', async ({ page }) => {
    const csrf = await login(page, 'finance');
    // Try to approve an existing submitted statement
    const listRes = await apiGet(page, '/api/v1/finance/settlements');
    const submitted = (listRes.body.data?.items || []).find((s: any) => s.status === 'submitted');
    if (submitted) {
      const res = await apiPost(page, `/api/v1/finance/settlements/${submitted.id}/approve-final`, {}, csrf);
      expect(res.status).toBe(403);
    }
  });

  test('admin approves and locks statement', async ({ page }) => {
    const csrf = await login(page, 'admin');

    // Find a submitted statement
    const listRes = await apiGet(page, '/api/v1/finance/settlements');
    const submitted = (listRes.body.data?.items || []).find((s: any) => s.status === 'submitted');
    expect(submitted).toBeTruthy();

    const approveRes = await apiPost(page, `/api/v1/finance/settlements/${submitted.id}/approve-final`, {}, csrf);
    expect(approveRes.status).toBe(200);
    expect(approveRes.body.data.status).toBe('approved_locked');

    await page.goto('/settlements');
    await page.waitForTimeout(1500);
    await page.screenshot({ path: 'tests/Playwright/artifacts/04-settlement-locked.png' });
  });

  test('locked statement rejects resubmit', async ({ page }) => {
    const csrf = await login(page, 'finance');
    const listRes = await apiGet(page, '/api/v1/finance/settlements');
    const locked = (listRes.body.data?.items || []).find((s: any) => s.status === 'approved_locked');
    if (locked) {
      const res = await apiPost(page, `/api/v1/finance/settlements/${locked.id}/submit`, {}, csrf);
      expect(res.status).toBe(423);
    }
  });

  test('reversal creates correction path', async ({ page }) => {
    const csrf = await login(page, 'admin');
    const listRes = await apiGet(page, '/api/v1/finance/settlements');
    const locked = (listRes.body.data?.items || []).find((s: any) => s.status === 'approved_locked');
    if (locked) {
      const res = await apiPost(page, `/api/v1/finance/settlements/${locked.id}/reverse`, {
        reason: 'E2E test correction',
      }, csrf);
      expect(res.status).toBe(200);
      const data = res.body.data;
      expect(data.replacement_statement_id).toBeTruthy();
    }
  });
});
"}

