import { login, apiPost, apiGet } from './helpers';

test.describe('Analytics Dashboard & Reporting', () => {
  test('analyst views dashboard with metrics', async ({ page }) => {
    await login(page, 'analyst');
    await page.goto('/analytics');
    await page.waitForTimeout(2000);
    await page.screenshot({ path: 'tests/Playwright/artifacts/03-analytics-dashboard.png' });

    const res = await apiGet(page, '/api/v1/analytics/dashboard');
    expect(res.status).toBe(200);
    const data = res.body.data || {};
    const metrics = data.widgets?.metrics || data.metrics || {};
    expect(metrics).toHaveProperty('total_sales');
    expect(metrics).toHaveProperty('avg_order_value');
  });

  test('analyst triggers on-demand refresh', async ({ page }) => {
    const csrf = await login(page, 'analyst');
    const res = await apiPost(page, '/api/v1/analytics/refresh', { scope: [1] }, csrf);
    expect([200, 202, 429]).toContain(res.status);
  });

  test('refresh rate limit at 5/hour', async ({ page }) => {
    // Use a dedicated user to avoid cross-test pollution
    const csrf = await login(page, 'analyst');

    // Fire requests until we hit the limit or exhaust attempts
    let blocked = false;
    for (let i = 0; i < 10; i++) {
      const res = await apiPost(page, '/api/v1/analytics/refresh', { scope: [1] }, csrf);
      if (res.status === 429) {
        blocked = true;
        break;
      }
    }
    // The rate limit is 5/hour - with previous tests and seed data,
    // we should have hit it within 10 attempts
    expect(blocked).toBe(true);
    await page.screenshot({ path: 'tests/Playwright/artifacts/03-rate-limit-hit.png' });
  });

  test('analyst creates report and runs it', async ({ page }) => {
    const csrf = await login(page, 'analyst');
