1	import { Page, expect } from '@playwright/test';
2	import { readFileSync } from 'fs';
3	import * as path from 'path';
4	
5	export function getPassword(): string {
6	  try {
7	    return readFileSync('/tmp/siteops_test_password', 'utf-8').trim();
8	  } catch {
9	    throw new Error('Password file not found at /tmp/siteops_test_password');
10	  }
11	}
12	
13	export async function login(page: Page, username: string): Promise<void> {
14	  const password = getPassword();
15	  await page.goto('/login');
16	  await page.fill('input[name="username"]', username);
17	  await page.fill('input[name="password"]', password);
18	  await page.click('button[lay-submit]');
19	  await page.waitForURL('**/dashboard', { timeout: 10000 });
20	}
21	
22	// API helpers — use ONLY for setup/teardown, never for the action under test
23	export async function apiPost(page: Page, path: string, data: any, csrf: string): Promise<any> {
24	  const r = await page.request.post(`http://127.0.0.1:8080${path}`, {
25	    data,
26	    headers: { 'Content-Type': 'application/json', 'X-CSRF-Token': csrf },
27	  });
28	  try { return { status: r.status(), body: await r.json() }; }
29	  catch { return { status: r.status(), body: await r.text() }; }
30	}
31	
32	export async function apiGet(page: Page, p: string): Promise<any> {
33	  const r = await page.request.get(`http://127.0.0.1:8080${p}`);
34	  try { return { status: r.status(), body: await r.json() }; }
35	  catch { return { status: r.status(), body: await r.text() }; }
36	}
37	
38	export function getCsrf(page: Page): Promise<string> {
39	  return page.getAttribute('meta[name="csrf-token"]', 'content').then(v => v || '');
40	}
41	
42	export function testImagePath(): string {
43	  return path.resolve(__dirname, 'test-image.jpg');
44	}
