    public function testRetentionCleanupCommandRuns(): void
    {
        $output = [];
        exec('cd /app && php think retention:cleanup 2>&1', $output, $exitCode);
        $out = implode("\n", $output);
        $this->assertEquals(0, $exitCode, 'retention:cleanup exit code. Output: ' . $out);
        $this->assertStringContainsString('Retention cleanup', $out);
    }

    public function testAuditRetentionCommandRuns(): void
    {
        $output = [];
        exec('cd /app && php think audit:retention 2>&1', $output, $exitCode);
        $out = implode("\n", $output);
        $this->assertEquals(0, $exitCode, 'audit:retention exit code. Output: ' . $out);
        $this->assertStringContainsString('No audit log records will be purged', $out);
    }

    public function testRetentionCleanupPreservesActiveArtifacts(): void
    {
        $s = $this->loginAs('admin');
        $def = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $s, [
            'name' => 'Retention Active ' . uniqid(),
            'dimensions_json' => ['type' => 'regional_distribution'],
        ]);
        $this->assertContains($def['status'], [200, 201]);
        $run = $this->authenticatedRequest('POST', '/api/v1/reports/definitions/' . $def['body']['data']['id'] . '/run', $s);
        $this->assertContains($run['status'], [200, 202]);
        $runId = $run['body']['data']['run_id'];

