        $this->assertEquals(0, $exitCode);

        $check = $this->authenticatedRequest('GET', '/api/v1/reports/runs/' . $runId, $s);
        $this->assertEquals(200, $check['status']);
        $this->assertNotEquals('expired', $check['body']['data']['status'] ?? '');
    }

    public function testRetentionCleanupRemovesExpiredArtifacts(): void
    {
        // Directly insert an expired report run + artifact into the DB
        $app = new \think\App();
        $app->initialize();

        $defId = \think\facade\Db::name('report_definitions')->insertGetId([
            'name' => 'Expired Test Def',
            'created_by' => 1,
            'created_at' => date('Y-m-d H:i:s'),
            'updated_at' => date('Y-m-d H:i:s'),
        ]);

        // Create a run that expired 10 days ago
        $expiredDate = date('Y-m-d H:i:s', strtotime('-10 days'));
        $runId = \think\facade\Db::name('report_runs')->insertGetId([
            'definition_id' => $defId,
            'status' => 'succeeded',
            'artifact_path' => '/app/storage/reports/expired_test.csv',
            'expires_at' => $expiredDate,
            'started_at' => $expiredDate,
            'completed_at' => $expiredDate,
            'created_at' => $expiredDate,
        ]);

        \think\facade\Db::name('report_artifacts')->insert([
            'run_id' => $runId,
