13	    /**
14	     * Retention period in days for report artifacts.
15	     */
16	    protected const RETENTION_DAYS = 180;
17	
18	    protected function configure()
19	    {
20	        $this->setName('retention:cleanup')
21	            ->setDescription('Clean up expired report artifacts (180-day retention)');
22	    }
23	
24	    protected function execute(Input $input, Output $output)
25	    {
26	        $output->writeln('[' . date('Y-m-d H:i:s') . '] Retention cleanup started.');
27	        Log::info('Retention cleanup started.');
28	
29	        try {
30	            $cutoffDate = date('Y-m-d H:i:s', strtotime('-' . self::RETENTION_DAYS . ' days'));
31	
32	            // Find expired report runs (those with expires_at in the past)
33	            $expiredRuns = Db::name('report_runs')
34	                ->where('expires_at', '<=', $cutoffDate)
35	                ->where('status', '<>', 'expired')
36	                ->select();
37	
38	            $count = count($expiredRuns);
39	            $output->writeln("Found {$count} expired report run(s) to clean up.");
40	            Log::info("Found {$count} expired report run(s) to clean up.");
41	
42	            foreach ($expiredRuns as $run) {
43	                try {
44	                    // Find and remove associated artifact files
45	                    $artifacts = Db::name('report_artifacts')
46	                        ->where('run_id', $run['id'])
47	                        ->select();
48	
49	                    foreach ($artifacts as $artifact) {
50	                        if (!empty($artifact['file_path']) && file_exists($artifact['file_path'])) {
51	                            unlink($artifact['file_path']);
52	                            $output->writeln("Removed artifact file: {$artifact['file_path']}");
53	                            Log::info("Removed artifact file: {$artifact['file_path']}");
54	                        }
55	                    }
56	
57	                    // Update report run status to expired
58	                    Db::name('report_runs')
59	                        ->where('id', $run['id'])
60	                        ->update(['status' => 'expired']);
61	
62	                    $output->writeln("Marked report run #{$run['id']} as expired.");
63	                    Log::info("Marked report run #{$run['id']} as expired.");
64	                } catch (\Exception $e) {
65	                    $output->writeln("<error>Failed to clean up run #{$run['id']}: {$e->getMessage()}</error>");
66	                    Log::error("Failed to clean up run #{$run['id']}: {$e->getMessage()}");
67	                }
68	            }
69	        } catch (\Exception $e) {
70	            $output->writeln('<error>Error during retention cleanup: ' . $e->getMessage() . '</error>');
71	            Log::error('Error during retention cleanup: ' . $e->getMessage(), [
72	                'trace' => $e->getTraceAsString(),
73	            ]);
74	        }
75	
76	        $output->writeln('[' . date('Y-m-d H:i:s') . '] Retention cleanup completed.');
77	        Log::info('Retention cleanup completed.');
78	    }
79	}
