6	class FreightCalculatorService
7	{
8	    /**
9	     * Calculate freight charges for a set of items according to the given rules.
10	     *
11	     * @param array $items Line items with weight, volume, distance, etc.
12	     * @param array $rules Freight calculation rules (distance bands, weight/volume tiers, surcharges, tax_rate).
13	     * @return array Calculated freight breakdown with subtotal, tax, total, and line_items.
14	     */
15	    public function calculate(array $items, array $rules): array
16	    {
17	        $lineItems = [];
18	        $subtotal = 0.0;
19	
20	        foreach ($items as $item) {
21	            $lineTotal = 0.0;
22	
23	            // Apply distance band rate
24	            $distance = $item['distance'] ?? 0;
25	            foreach (($rules['distance_bands'] ?? []) as $band) {
26	                $bandMin = $band['min'] ?? $band['min_km'] ?? 0;
27	                $bandMax = $band['max'] ?? $band['max_km'] ?? PHP_INT_MAX;
28	                $bandRate = $band['rate'] ?? $band['fee'] ?? 0;
29	                if ($distance >= $bandMin && $distance <= $bandMax) {
30	                    $lineTotal += $distance * $bandRate;
31	                    break;
32	                }
33	            }
34	
35	            // Apply weight tier rate
36	            $weight = $item['weight'] ?? 0;
37	            foreach (($rules['weight_tiers'] ?? []) as $tier) {
38	                $tierMin = $tier['min'] ?? $tier['min_kg'] ?? 0;
39	                $tierMax = $tier['max'] ?? $tier['max_kg'] ?? PHP_INT_MAX;
40	                $tierRate = $tier['rate'] ?? $tier['fee'] ?? 0;
41	                if ($weight >= $tierMin && $weight <= $tierMax) {
42	                    $lineTotal += $weight * $tierRate;
43	                    break;
44	                }
45	            }
46	
47	            // Apply volume tier rate
48	            $volume = $item['volume'] ?? 0;
49	            foreach (($rules['volume_tiers'] ?? []) as $tier) {
50	                if ($volume >= ($tier['min'] ?? 0) && $volume <= ($tier['max'] ?? PHP_INT_MAX)) {
51	                    $lineTotal += $volume * ($tier['rate'] ?? 0);
52	                    break;
53	                }
54	            }
55	
56	            $lineItems[] = [
57	                'item' => $item,
58	                'amount' => $lineTotal,
59	            ];
60	            $subtotal += $lineTotal;
61	        }
62	
63	        // Apply surcharges
64	        foreach (($rules['surcharges'] ?? []) as $surcharge) {
65	            $subtotal += $surcharge['amount'] ?? 0;
66	        }
67	
68	        $taxRate = (float)($rules['tax_rate'] ?? 0);
69	        $tax = round($subtotal * $taxRate, 2);
70	        $total = round($subtotal + $tax, 2);
71	
72	        return [
73	            'line_items' => $lineItems,
74	            'subtotal' => $subtotal,
75	            'tax' => $tax,
76	            'total' => $total,
77	        ];
78	    }
79	}
